import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"南锣鼓巷","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/nanluoguxiang.md","filePath":"landmarks/nanluoguxiang.md","lastUpdated":1784773307000}'),n={name:"landmarks/nanluoguxiang.md"};function d(o,t,s,i,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="南锣鼓巷" tabindex="-1">南锣鼓巷 <a class="header-anchor" href="#南锣鼓巷" aria-label="Permalink to &quot;南锣鼓巷&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-Uk19VsygF9Y?w=1200" alt="南锣鼓巷"></p><blockquote><p>&quot;胡同里的文艺梦，老北京的新活力。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>南锣鼓巷位于北京市东城区，是一条有着740多年历史的古老胡同。南锣鼓巷以其独特的&quot;鱼骨状&quot;胡同布局和浓厚的文艺氛围闻名，是北京胡同文化的代表之一。这里汇聚了众多特色小店、文艺咖啡馆、创意餐厅，是年轻人和游客的打卡胜地。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">全天开放</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁6/8号线南锣鼓巷站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市东城区南锣鼓巷</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="元代形成" tabindex="-1">元代形成 <a class="header-anchor" href="#元代形成" aria-label="Permalink to &quot;元代形成&quot;">​</a></h3><p>南锣鼓巷始建于元代，当时称为&quot;罗锅巷&quot;。元代定都北京后，这里成为贵族聚居区。</p><h3 id="明清时期" tabindex="-1">明清时期 <a class="header-anchor" href="#明清时期" aria-label="Permalink to &quot;明清时期&quot;">​</a></h3><p>明清时期，南锣鼓巷周边逐渐形成了众多的府邸和宅院。这里曾居住过众多达官显贵和文人墨客。</p><h4 id="名人故居" tabindex="-1">名人故居 <a class="header-anchor" href="#名人故居" aria-label="Permalink to &quot;名人故居&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">名人</th><th style="text-align:left;">身份</th><th style="text-align:left;">故居位置</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>齐白石</strong></td><td style="text-align:left;">画家</td><td style="text-align:left;">雨儿胡同</td></tr><tr><td style="text-align:left;"><strong>茅盾</strong></td><td style="text-align:left;">作家</td><td style="text-align:left;">后圆恩寺胡同</td></tr><tr><td style="text-align:left;"><strong>蒋介石</strong></td><td style="text-align:left;">政治家</td><td style="text-align:left;">后圆恩寺胡同</td></tr><tr><td style="text-align:left;"><strong>僧格林沁</strong></td><td style="text-align:left;">将领</td><td style="text-align:left;">僧王府</td></tr><tr><td style="text-align:left;"><strong>洪承畴</strong></td><td style="text-align:left;">将领</td><td style="text-align:left;">洪承畴府</td></tr></tbody></table><h3 id="近代变迁" tabindex="-1">近代变迁 <a class="header-anchor" href="#近代变迁" aria-label="Permalink to &quot;近代变迁&quot;">​</a></h3><p>20世纪90年代以来，南锣鼓巷逐渐发展成为北京最具特色的文艺街区之一。2008年，南锣鼓巷被评为&quot;北京十大胡同&quot;之一。</p><h2 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h2><h3 id="鱼骨状-布局" tabindex="-1">&quot;鱼骨状&quot;布局 <a class="header-anchor" href="#鱼骨状-布局" aria-label="Permalink to &quot;&quot;鱼骨状&quot;布局&quot;">​</a></h3><p>南锣鼓巷的胡同布局呈典型的&quot;鱼骨状&quot;，主巷为南北走向，东西两侧对称分布着众多支巷。</p><h4 id="布局特点" tabindex="-1">布局特点 <a class="header-anchor" href="#布局特点" aria-label="Permalink to &quot;布局特点&quot;">​</a></h4><ul><li><strong>主巷</strong>：南北走向，长约800米</li><li><strong>支巷</strong>：东西对称分布</li><li><strong>格局</strong>：主巷两侧各有8条支巷</li></ul><h3 id="胡同风貌" tabindex="-1">胡同风貌 <a class="header-anchor" href="#胡同风貌" aria-label="Permalink to &quot;胡同风貌&quot;">​</a></h3><p>南锣鼓巷保存了大量元、明、清三代的建筑，是北京胡同风貌最集中的地区之一。</p><h4 id="建筑特色-1" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色-1" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h4><ul><li><strong>四合院</strong>：保存完好的传统四合院</li><li><strong>门楼</strong>：精美的砖雕门楼</li><li><strong>古树</strong>：百年以上的古树</li></ul><h2 id="主要景点" tabindex="-1">主要景点 <a class="header-anchor" href="#主要景点" aria-label="Permalink to &quot;主要景点&quot;">​</a></h2><h3 id="特色小店" tabindex="-1">特色小店 <a class="header-anchor" href="#特色小店" aria-label="Permalink to &quot;特色小店&quot;">​</a></h3><p>南锣鼓巷内汇聚了众多特色小店，是购物和淘宝的好去处。</p><h4 id="店铺类型" tabindex="-1">店铺类型 <a class="header-anchor" href="#店铺类型" aria-label="Permalink to &quot;店铺类型&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">代表店铺</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>文创产品</strong></td><td style="text-align:left;">原创设计、手工艺品</td></tr><tr><td style="text-align:left;"><strong>特色小吃</strong></td><td style="text-align:left;">北京小吃、各国美食</td></tr><tr><td style="text-align:left;"><strong>服饰鞋帽</strong></td><td style="text-align:left;">原创设计、复古风格</td></tr><tr><td style="text-align:left;"><strong>纪念品</strong></td><td style="text-align:left;">北京特色纪念品</td></tr></tbody></table><h3 id="文艺咖啡馆" tabindex="-1">文艺咖啡馆 <a class="header-anchor" href="#文艺咖啡馆" aria-label="Permalink to &quot;文艺咖啡馆&quot;">​</a></h3><p>南锣鼓巷内有众多文艺咖啡馆，是休息和拍照的好去处。</p><h4 id="咖啡馆特色" tabindex="-1">咖啡馆特色 <a class="header-anchor" href="#咖啡馆特色" aria-label="Permalink to &quot;咖啡馆特色&quot;">​</a></h4><ul><li><strong>环境</strong>：复古、文艺、 cozy</li><li><strong>饮品</strong>：咖啡、茶、甜品</li><li><strong>氛围</strong>：适合拍照、发呆、聊天</li></ul><h3 id="名人故居-1" tabindex="-1">名人故居 <a class="header-anchor" href="#名人故居-1" aria-label="Permalink to &quot;名人故居&quot;">​</a></h3><p>南锣鼓巷周边分布着众多名人故居，可以感受老北京的文化底蕴。</p><h4 id="主要故居" tabindex="-1">主要故居 <a class="header-anchor" href="#主要故居" aria-label="Permalink to &quot;主要故居&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">故居</th><th style="text-align:left;">位置</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>齐白石故居</strong></td><td style="text-align:left;">雨儿胡同</td><td style="text-align:left;">画家故居</td></tr><tr><td style="text-align:left;"><strong>茅盾故居</strong></td><td style="text-align:left;">后圆恩寺胡同</td><td style="text-align:left;">作家故居</td></tr><tr><td style="text-align:left;"><strong>僧王府</strong></td><td style="text-align:left;">僧王府胡同</td><td style="text-align:left;">王府建筑</td></tr></tbody></table><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约2小时）</strong>：</p><p>南锣鼓巷主巷 → 特色小店 → 文艺咖啡馆 → 名人故居 → 胡同深处</p><p><strong>深度路线（约半天）</strong>：</p><p>上午：南锣鼓巷主巷 → 特色小店 → 文艺咖啡馆 下午：名人故居 → 胡同深处 → 周边景点</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：工作日人较少，适合慢慢逛</li><li><strong>避开高峰</strong>：周末和节假日人很多，建议错峰出行</li><li><strong>拍照打卡</strong>：南锣鼓巷的胡同、小店都是绝佳拍照点</li><li><strong>购物建议</strong>：可以议价，但不要太狠</li><li><strong>餐饮推荐</strong>：巷内有众多特色小吃，可以品尝</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">6/8号线南锣鼓巷站E口或F口</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">13、60、82、107、124路南锣鼓巷站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;南锣鼓巷&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">什刹海</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">老北京水乡</td></tr><tr><td style="text-align:left;">钟鼓楼</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">老北京地标</td></tr><tr><td style="text-align:left;">北海公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">皇家园林</td></tr><tr><td style="text-align:left;">景山公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">俯瞰紫禁城</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>南锣鼓巷是北京胡同文化的代表，也是老北京生活方式的缩影。在这里，你可以感受到老北京的烟火气，也可以体验到现代文艺的活力。</p><p>&quot;胡同深处有人家&quot;，南锣鼓巷的每一条胡同、每一座四合院，都承载着老北京的历史和记忆。</p><hr><p><strong>📍 地址</strong>：北京市东城区南锣鼓巷 <strong>🚇 地铁</strong>：6/8号线南锣鼓巷站E口或F口</p><p><strong>💡 Tips</strong>：南锣鼓巷的胡同深处有很多惊喜，建议不要只逛主巷，深入到支巷中去探索。</p>',56)])])}const u=e(n,[["render",d]]);export{f as __pageData,u as default};
